// Delivery status
export type DeliveryStatus =
  | "DELIVERY_STATUS_UNSPECIFIED"
  | "DELIVERY_STATUS_PENDING"
  | "DELIVERY_STATUS_SENT"
  | "DELIVERY_STATUS_FAILED";
// Notification log entity
export type NotificationLog = {
  id: string | undefined;
  tenantId: number | undefined;
  channelId: string | undefined;
  channelType: ChannelType | undefined;
  templateId: string | undefined;
  // Recipient address (email, phone number, slack channel, etc.)
  recipient: string | undefined;
  renderedSubject: string | undefined;
  renderedBody: string | undefined;
  status: DeliveryStatus | undefined;
  errorMessage: string | undefined;
  createdBy?: number;
  createTime: wellKnownTimestamp | undefined;
  sentAt?: wellKnownTimestamp;
};

// Request to send a notification
export type SendNotificationRequest = {
  // Template ID to use for rendering
  //
  // Behaviors: REQUIRED
  templateId: string | undefined;
  // Optional channel ID. If not set, uses the default channel for the template's channel type.
  channelId?: string;
  // Recipient address (email address, phone number, slack channel, etc.)
  //
  // Behaviors: REQUIRED
  recipient: string | undefined;
  // Template variables (key/value pairs for template rendering)
  variables: { [key: string]: string } | undefined;
};

export type SendNotificationResponse = {
  notification: NotificationLog | undefined;
};

// Request to get a notification log
export type GetNotificationRequest = {
  //
  // Behaviors: REQUIRED
  id: string | undefined;
};

export type GetNotificationResponse = {
  notification: NotificationLog | undefined;
};

// Request to list notification logs
export type ListNotificationsRequest = {
  page?: number;
  pageSize?: number;
  channelType?: ChannelType;
  status?: DeliveryStatus;
  recipient?: string;
};

export type ListNotificationsResponse = {
  notifications: NotificationLog[] | undefined;
  total: number | undefined;
};

// Notification Service - sends notifications and tracks delivery
export interface NotificationService {
  // Send a notification using a template
  SendNotification(request: SendNotificationRequest): Promise<SendNotificationResponse>;
  // Get a notification log entry by ID
  GetNotification(request: GetNotificationRequest): Promise<GetNotificationResponse>;
  // List notification logs
  ListNotifications(request: ListNotificationsRequest): Promise<ListNotificationsResponse>;
}

